   180→	static StringName _get_parent_class(const StringName &p_class);
   181→	static bool _is_parent_class(const StringName &p_class, const StringName &p_inherits);
   182→	static void _bind_compatibility(ClassInfo *type, MethodBind *p_method);
   183→	static MethodBind *_bind_vararg_method(MethodBind *p_bind, const StringName &p_name, const Vector<Variant> &p_default_args, bool p_compatibility);
   184→	static void _bind_method_custom(const StringName &p_class, MethodBind *p_method, bool p_compatibility);
