   195→	template <typename T>
   196→	static void register_class(bool p_virtual = false) {
   197→		GLOBAL_LOCK_FUNCTION;
   198→		static_assert(std::is_same_v<typename T::self_type, T>, "Class not declared properly, please use GDCLASS.");
   199→		T::initialize_class();
